// TOPIC_CHANNELS 파싱: 채널별 (channelId, topic) 쌍 목록으로 펼치기
// 형식: "채널이름/채널ID+채널이름/채널ID+..."
// 예: "노마드코더/UCUpJs89fSBXNolQGOYKn0YQ+조코딩/UCQNE2JmbasNYbjGAcuBiRRg"
const raw = $env.TOPIC_CHANNELS || '';
if (!raw.trim()) return [{ json: { skip: true, reason: 'TOPIC_CHANNELS 미설정' } }];

const channels = [];
for (const ch of raw.split('+')) {
  const slashIdx = ch.indexOf('/');
  if (slashIdx < 0) continue;
  const channelName = ch.slice(0, slashIdx).trim();
  const channelId   = ch.slice(slashIdx + 1).trim();
  if (channelName && channelId) channels.push({ channelId, topic: channelName });
}

if (channels.length === 0) return [{ json: { skip: true, reason: '파싱된 채널 없음' } }];
return channels.map(ch => ({ json: ch }));

// YouTube RSS 조회 + 일시 오류(404/500) 재시도 + 새 영상 필터링(Shorts 제외)
const channelId = ($json.channelId || '').trim();
const topic = ($json.topic || '').trim();

if (!channelId) {
  return [{ json: { skip: true, channelId, topic, reason: 'channelId 없음' } }];
}

const RSS_URL = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;
const MAX_RETRIES = 40;
const BASE_WAIT_MS = 1000;
const MAX_WAIT_MS = 10000;
const MAX_TOTAL_WAIT_MS = 240 * 1000; // 총 4분
const CUTOFF_MS = Date.now() - 90 * 60 * 1000; // 1.5시간

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const decodeEntities = (text = '') =>
  text
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");

const asArray = (v) => (Array.isArray(v) ? v : (v == null ? [] : [v]));
const textOf = (v) => {
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) return textOf(v[0]);
  if (!v || typeof v !== 'object') return '';
  if (typeof v._ === 'string') return v._;
  if (typeof v['#text'] === 'string') return v['#text'];
  return '';
};

const extractHref = (linkVal) => {
  for (const link of asArray(linkVal)) {
    if (!link) continue;
    if (typeof link === 'string') return link;
    if (typeof link.href === 'string') return link.href;
    if (link.$ && typeof link.$.href === 'string') return link.$.href;
    if (link.attrs && typeof link.attrs.href === 'string') return link.attrs.href;
  }
  return '';
};

const normalizeVideoUrl = (videoId, link) => {
  if (typeof link === 'string' && link.includes('youtube.com/watch')) return link;
  if (videoId) return `https://www.youtube.com/watch?v=${videoId}`;
  return '';
};

const parseFromXml = (xml) => {
  const out = [];
  const entryRegex = /<entry>([\s\S]*?)<\/entry>/g;
  let match;
  while ((match = entryRegex.exec(xml)) !== null) {
    const block = match[1];
    const videoId = (block.match(/<yt:videoId>([^<]+)<\/yt:videoId>/) || [])[1] || '';
    const title = (block.match(/<title>([^<]+)<\/title>/) || [])[1] || '';
    const publishedAt = (block.match(/<published>([^<]+)<\/published>/) || [])[1] || '';
    const linkMatch = block.match(/<link rel="alternate" href="([^"]+)"/);
    const link = linkMatch ? linkMatch[1] : '';
    if (!videoId) continue;
    out.push({
      videoId,
      title: decodeEntities(title),
      publishedAt,
      videoUrl: normalizeVideoUrl(videoId, link),
    });
  }
  return out;
};

const parseFromObject = (data) => {
  const feed = data && data.feed ? data.feed : data;
  const rawEntries = feed && feed.entry ? asArray(feed.entry) : [];
  const out = [];

  for (const raw of rawEntries) {
    if (!raw || typeof raw !== 'object') continue;
    const videoId = textOf(raw['yt:videoId']) || textOf(raw.videoId);
    if (!videoId) continue;

    const title = decodeEntities(textOf(raw.title));
    const publishedAt = textOf(raw.published) || textOf(raw.updated);
    const link = extractHref(raw.link);

    out.push({
      videoId,
      title,
      publishedAt,
      videoUrl: normalizeVideoUrl(videoId, link),
    });
  }

  return out;
};

let parsedEntries = [];
let fetchMode = '';
let lastError = '';
const startMs = Date.now();

for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  const elapsed = Date.now() - startMs;
  if (elapsed >= MAX_TOTAL_WAIT_MS) {
    lastError = `총 대기시간 ${Math.floor(MAX_TOTAL_WAIT_MS / 1000)}초 초과`;
    break;
  }

  try {
    const response = await $helpers.httpRequest({
      method: 'GET',
      url: RSS_URL,
      options: { timeout: 10000 },
    });

    if (typeof response === 'string') {
      if (response.includes('<feed')) {
        parsedEntries = parseFromXml(response);
        fetchMode = 'xml-string';
        console.log(`[WF-09] RSS 조회 성공(channel=${channelId}, attempt=${attempt}, mode=${fetchMode}, entries=${parsedEntries.length})`);
        break;
      }
      lastError = `문자열 응답이지만 feed 태그 없음(길이=${response.length})`;
    } else if (response && typeof response === 'object') {
      const candidate = (response.body && (typeof response.body === 'string' || typeof response.body === 'object'))
        ? response.body
        : response;

      if (typeof candidate === 'string' && candidate.includes('<feed')) {
        parsedEntries = parseFromXml(candidate);
        fetchMode = 'xml-string-in-body';
        console.log(`[WF-09] RSS 조회 성공(channel=${channelId}, attempt=${attempt}, mode=${fetchMode}, entries=${parsedEntries.length})`);
        break;
      }

      if (candidate && typeof candidate === 'object' && (candidate.feed || candidate.entry)) {
        parsedEntries = parseFromObject(candidate);
        fetchMode = 'parsed-object';
        console.log(`[WF-09] RSS 조회 성공(channel=${channelId}, attempt=${attempt}, mode=${fetchMode}, entries=${parsedEntries.length})`);
        break;
      }

      lastError = `객체 응답이지만 feed/entry 구조 없음(type=${typeof candidate})`;
    } else {
      lastError = `지원되지 않는 응답 타입(${typeof response})`;
    }
  } catch (e) {
    lastError = e && e.message ? e.message : String(e);
    console.log(`[WF-09] attempt ${attempt}: RSS 오류(channel=${channelId}) - ${lastError}`);
  }

  if (attempt < MAX_RETRIES) {
    const waitMs = Math.min(BASE_WAIT_MS * Math.pow(1.25, attempt - 1), MAX_WAIT_MS);
    await sleep(Math.floor(waitMs));
  }
}

if (!fetchMode) {
  return [{
    json: {
      skip: true,
      channelId,
      topic,
      reason: `RSS 조회 실패 (${lastError || 'unknown'})`,
      retries: MAX_RETRIES,
    },
  }];
}

if (parsedEntries.length === 0) {
  return [{
    json: {
      skip: true,
      channelId,
      topic,
      reason: `피드 응답은 성공했지만 entry 없음(mode=${fetchMode})`,
    },
  }];
}

const freshEntries = [];
for (const entry of parsedEntries) {
  const videoUrl = entry.videoUrl || (entry.videoId ? `https://www.youtube.com/watch?v=${entry.videoId}` : '');
  if (!videoUrl) continue;

  // YouTube Shorts 제외 (NotebookLM 트랜스크립트 미지원)
  if (videoUrl.includes('/shorts/')) continue;

  const publishedMs = Date.parse(entry.publishedAt || '');
  if (!Number.isFinite(publishedMs)) continue;

  if (publishedMs >= CUTOFF_MS) {
    freshEntries.push({
      videoUrl,
      title: entry.title || '',
      publishedAt: entry.publishedAt || '',
      channelId,
      topic,
      fetchMode,
    });
  }
}

if (freshEntries.length === 0) {
  return [{
    json: {
      skip: true,
      channelId,
      topic,
      reason: `새 영상 없음(1.5시간 이내, mode=${fetchMode}, entries=${parsedEntries.length})`,
    },
  }];
}

return freshEntries.map((e) => ({ json: e }));

// 결과 로깅
const result = $input.item.json;

if (result.duplicate) {
  console.log(`[WF-09] 중복 건너뜀`);
} else if (result.added) {
  console.log(`[WF-09] 소스 추가 완료 (cleaned=${result.cleaned_up})`);
} else if (result.error) {
  console.error(`[WF-09] 소스 추가 실패: ${result.error}`);
}

return [{ json: result }];
